import{_ as a,o as n,c as t,a3 as o}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse(`{"title":"24. Annual Leave","description":"","frontmatter":{"title":"24. Annual Leave","eba":"Children's Services Award 2010","topics":["leave","annual-leave","hours","rosters","employment","termination","preliminary"]},"headers":[],"relativePath":"ebas/childrens-services/leave/24-annual-leave.md","filePath":"ebas/childrens-services/leave/24-annual-leave.md"}`),r={name:"ebas/childrens-services/leave/24-annual-leave.md"};function i(l,e,p,s,d,u){return n(),t("div",null,[...e[0]||(e[0]=[o(`<h1 id="_24-annual-leave" tabindex="-1">24. Annual Leave <a class="header-anchor" href="#_24-annual-leave" aria-label="Permalink to &quot;24. Annual Leave&quot;">​</a></h1><ol><li><p>Annual leave is provided for in the <a href="https://www.fwc.gov.au/documents/awards/resources/nes.pdf" target="_blank" rel="noreferrer">NES</a>.</p></li><li><p>For the purposes of the additional week of leave provided by the <a href="https://www.fwc.gov.au/documents/awards/resources/nes.pdf" target="_blank" rel="noreferrer">NES</a>, a shiftworker is an employee on shiftwork who is required to work in accordance with a roster on Sundays and public holidays.</p></li><li><p>Annual leave loading</p></li></ol><p>In addition to the payment provided for by the <a href="https://www.fwc.gov.au/documents/awards/resources/nes.pdf" target="_blank" rel="noreferrer">NES</a> an employer is required to pay leave loading of 17.5% of that payment.</p><ol><li>Direction to take annual leave during shutdown</li></ol><p>a. Clause 24.4 applies if an employer:</p><pre><code>i.  intends to shut down all or part of its operation for a
    particular period during the Christmas vacation (**temporary
    shutdown period**); and

ii. wishes to require affected employees to take paid annual leave
    during that period.
</code></pre><p>b. Clause 24.4 does not apply to a shutdown period during any vacation period other than the Christmas vacation. During any shutdown period to which clause 24.4 does not apply, employees will be paid the ordinary rate of pay.</p><p>c. The employer must give the affected employees 28 days&#39; written notice of a temporary shutdown period, or any shorter period agreed between the employer and the majority of relevant employees.</p><p>d. The employer must give written notice of a temporary shutdown period to any employee who is engaged after the notice is given under clause 24.4(c) and who will be affected by that period, as soon as reasonably practicable after the employee is engaged.</p><p>e. The employer may direct the employee to take a period of paid annual leave to which the employee has accrued an entitlement during a temporary shutdown period.</p><p>f. A direction by the employer under clause 24.4(e):</p><pre><code>i.  must be in writing; and

ii. must be reasonable.
</code></pre><p>g. The employee must take paid annual leave in accordance with a direction under clause 24.4(e).</p><p>h. In respect of any part of a temporary shutdown period which is not the subject of a direction under clause 24.4(e), an employer and an employee may agree, in writing, for the employee to take leave without pay during that part of the temporary shutdown period.</p><p>i. An employee may take annual leave in advance during a temporary shutdown period in accordance with an agreement under clause 24.8.</p><p>j. In determining the amount of paid annual leave to which an employee has accrued an entitlement, any period of paid annual leave taken in advance by the employee, in accordance with an agreement under clause 24.8, to which an entitlement has not been accrued, is to be taken into account.</p><p>k. Clauses 24.5 to 24.7 do not apply to a period of annual leave that an employee is required to take during a temporary shutdown period in accordance with clause 24.8.</p><ol><li>Excessive leave accruals: general provision</li></ol><p>Note: Clauses 24.5 to 24.7 contain provisions, additional to the National Employment Standards, about the taking of paid annual leave as a way of dealing with the accrual of excessive paid annual leave. <strong>[See Part 2.2, Division 6 of the Fair Work Act]{.underline}.</strong></p><p>a. An employee has an <strong>excessive leave accrual</strong> if the employee has accrued more than 8 weeks&#39; paid annual leave (or 10 weeks&#39; paid annual leave for a shiftworker, as defined by clause 24.2).</p><p>b. If an employee has an excessive leave accrual, the employer or the employee may seek to confer with the other and genuinely try to reach agreement on how to reduce or eliminate the excessive leave accrual.</p><p>c. Clause 24.6 sets out how an employer may direct an employee who has an excessive leave accrual to take paid annual leave.</p><p>d. Clause 24.7 sets out how an employee who has an excessive leave accrual may require an employer to grant paid annual leave requested by the employee.</p><ol><li>Excessive leave accruals: direction by employer that leave be taken</li></ol><p>a. If an employer has genuinely tried to reach agreement with an employee under clause 24.5(b) but agreement is not reached (including because the employee refuses to confer), the employer may direct the employee in writing to take one or more periods of paid annual leave.</p><p>b. However, a direction by the employer under paragraph (a):</p><pre><code>i.  is of no effect if it would result at any time in the employee&#39;s
    remaining accrued entitlement to paid annual leave being less
    than 6 weeks when any other paid annual leave arrangements
    (whether made under clause 24.5, 24.6 or 24.7 or otherwise
    agreed by the employer and employee) are taken into account; and

ii. must not require the employee to take any period of paid annual
    leave of less than one week; and

iii. must not require the employee to take a period of paid annual
     leave beginning less than 8 weeks, or more than 12 months,
     after the direction is given; and

iv. must not be inconsistent with any leave arrangement agreed by
    the employer and employee.
</code></pre><p>c. The employee must take paid annual leave in accordance with a direction under paragraph (a) that is in effect.</p><p>d. An employee to whom a direction has been given under paragraph (a) may request to take a period of paid annual leave as if the direction had not been given.</p><p>Note 1: Paid annual leave arising from a request mentioned in paragraph (d) may result in the direction ceasing to have effect. See clause 24.6(b)(i).</p><p>Note 2: Under [section 88(2) of the Fair Work Act]{.underline}, the employer must not unreasonably refuse to agree to a request by the employee to take paid annual leave.</p><ol><li>Excessive leave accruals: request by employee for leave</li></ol><p>a. If an employee has genuinely tried to reach agreement with an employer under clause 24.5(b) but agreement is not reached (including because the employer refuses to confer), the employee may give a written notice to the employer requesting to take one or more periods of paid annual leave.</p><p>b. However, an employee may only give a notice to the employer under paragraph (a) if:</p><pre><code>i.  the employee has had an excessive leave accrual for more than 6
    months at the time of giving the notice; and

ii. the employee has not been given a direction under clause 24.6(a)
    that, when any other paid annual leave arrangements (whether
    made under clause 24.5, 24.6 or 24.7 or otherwise agreed by the
    employer and employee) are taken into account, would eliminate
    the employee&#39;s excessive leave accrual.
</code></pre><p>c. A notice given by an employee under paragraph (a) must not:</p><pre><code>i.  if granted, result in the employee&#39;s remaining accrued
    entitlement to paid annual leave being at any time less than 6
    weeks when any other paid annual leave arrangements (whether
    made under clause 24.5, 24.6 or 24.7 or otherwise agreed by the
    employer and employee) are taken into account; or

ii. provide for the employee to take any period of paid annual leave
    of less than one week; or

iii. provide for the employee to take a period of paid annual leave
     beginning less than 8 weeks, or more than 12 months, after the
     notice is given; or

iv. be inconsistent with any leave arrangement agreed by the
    employer and employee.
</code></pre><p>d. An employee is not entitled to request by a notice under paragraph (a) more than 4 weeks&#39; paid annual leave (or 5 weeks&#39; paid annual leave for a shiftworker, as defined by clause 24.2) in any period of 12 months.</p><p>e. The employer must grant paid annual leave requested by a notice under paragraph (a).</p><ol><li>Annual leave in advance</li></ol><p>a. An employer and employee may agree in writing to the employee taking a period of paid annual leave before the employee has accrued an entitlement to the leave.</p><p>b. An agreement must:</p><pre><code>i.  state the amount of leave to be taken in advance and the date on
    which leave is to commence; and

ii. be signed by the employer and employee and, if the employee is
    under 18 years of age, by the employee&#39;s parent or guardian.
</code></pre><p>Note: An example of the type of agreement required by clause 24.8 is set out at <a href="/eba/ebas/childrens-services/schedules/f-agreement-to-take-annual-leave-in-advance.html">Schedule F</a>. There is no requirement to use the form of agreement set out at <a href="/eba/ebas/childrens-services/schedules/f-agreement-to-take-annual-leave-in-advance.html">Schedule F</a>.</p><p>c. The employer must keep a copy of any agreement under clause 24.8 as an employee record.</p><p>d. If, on the termination of the employee&#39;s employment, the employee has not accrued an entitlement to all of a period of paid annual leave already taken in accordance with an agreement under clause 24.8, the employer may deduct from any money due to the employee on termination an amount equal to the amount that was paid to the employee in respect of any part of the period of annual leave taken in advance to which an entitlement has not been accrued.</p><ol><li>Cashing out of annual leave</li></ol><p>a. Paid annual leave must not be cashed out except in accordance with an agreement under clause 24.9.</p><p>b. Each cashing out of a particular amount of paid annual leave must be the subject of a separate agreement under clause 24.9.</p><p>c. An employer and an employee may agree in writing to the cashing out of a particular amount of accrued paid annual leave by the employee.</p><p>d. An agreement under clause 24.9 must state:</p><pre><code>i.  the amount of leave to be cashed out and the payment to be made
    to the employee for it; and

ii. the date on which the payment is to be made.
</code></pre><p>e. An agreement under clause 24.9 must be signed by the employer and employee and, if the employee is under 18 years of age, by the employee&#39;s parent or guardian.</p><p>f. The payment must not be less than the amount that would have been payable had the employee taken the leave at the time the payment is made.</p><p>g. An agreement must not result in the employee&#39;s remaining accrued entitlement to paid annual leave being less than 4 weeks.</p><p>h. The maximum amount of accrued paid annual leave that may be cashed out in any period of 12 months is 2 weeks.</p><p>i. The employer must keep a copy of any agreement under clause 24.9 as an employee record.</p><p>Note 1: Under [section 344 of the Fair Work Act]{.underline}, an employer must not exert undue influence or undue pressure on an employee to make, or not make, an agreement under clause 24.9.</p><p>Note 2: Under [section 345(1) of the Fair Work Act]{.underline}, a person must not knowingly or recklessly make a false or misleading representation about the workplace rights of another person under clause 24.9.</p><p>Note 3: An example of the type of agreement required by clause 24.9 is set out at <a href="/eba/ebas/childrens-services/schedules/g-agreement-to-cash-out-annual-leave.html">Schedule G</a>. There is no requirement to use the form of agreement set out at <a href="/eba/ebas/childrens-services/schedules/g-agreement-to-cash-out-annual-leave.html">Schedule G</a>.</p><p>Plain language terms: holidays, vacation.</p>`,61)])])}const m=a(r,[["render",i]]);export{c as __pageData,m as default};
